/**
 * Convert number to the two-digit format string woth leading zero.
 *
 * @param t - number to convert.
 * @return string representation of the given number always having two digits.
 */
function twoDigits(t)
{
    return String(t).padStart(2, "0");
}

/**
 * Format time.
 *
 * @param ms - time in milliseconds.
 * @return string representing time as hours, minutes, and fractional seconds.
 */
function formatTime(ms)
{
    const hh = Math.floor(ms / 3600000.0);
    const mm = Math.floor(ms / 60000.0 - hh * 60.0);
    const ss = Math.floor(ms / 1000.0 - hh * 3600.0 - mm * 60.0);
    const mms = ms - hh * 3600000.0 - mm * 60000.0 - ss * 1000.0;
    return `${twoDigits(hh)}:${twoDigits(mm)}:${twoDigits(ss)}.${mms}`;
}

/**
 * Generate HTML for a sanity check result.
 *
 * @param sc - boolean sanity check result.
 * @return HTML representation of the sanity check result.
 */
function sanCheck(sc)
{
    return sc ? `<td class="report-sanity-ok">OK</td>` : `<td class="report-sanity-fail">Fail</td>`;
}

/**
 * Convert date to string.
 *
 * @param d - date.
 * @return string representation of the given date.
 */
function formatDate(d)
{
    return `${twoDigits(d.getDate())}.${twoDigits(d.getMonth() + 1)}.${d.getFullYear()}`;
}

/**
 * Display the mission overview report.
 *
 * @param solutionID - colution ID.
 */
async function buildOverview(solutionID)
{
    const report = document.createElement("div");
    report.classList.add("report");
    report.innerHTML = `
        <div id="raccoon" style="position: absolute; left: 0px; top: calc(50vh - 90px);">
            <img style="width: 180px; height: 180px" src="data:image/gif;base64," />
        </div>
    `;
    ADD_TAB(report, "Overview");

    let raccoonLeft = 0;
    let lastTime = 0;
    let animate = (now) => {
        if (lastTime == 0)
            lastTime = now;
        let raccoon = document.getElementById("raccoon");
        if (raccoon)
        {
            raccoon.style.left = raccoonLeft + "px";
            raccoonLeft += (now - lastTime) / 1000.0 * 180;
            lastTime = now;
            if (raccoonLeft > window.innerWidth)
                raccoonLeft = -180;
            requestAnimationFrame(animate);
        }
    };

    requestAnimationFrame(animate);

    const overview = await get_mission_overview(solutionID);
    const stats = await get_solution_stats(solutionID);
    const sanity = await get_sanity_checks(solutionID);
    let bullet = 1;
    const html = `
        <h2>Overview</h2>
        <div class="report-dashrow">
            <div class="report-dashbox">
                <h3>Mission Overview</h3>
                <table>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of sources</td>
                        <td class="table-num">${overview["Lambda"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of Gaia priors</td>
                        <td class="table-num">${overview["LambdaGaia"]} (${(overview["LambdaGaia"] / overview["Lambda"] * 100.0).toFixed(1)}%)</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of exposures</td>
                        <td class="table-num">${overview["UpsilonUnits"][0]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of detectors</td>
                        <td class="table-num">${overview["N"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of astrometric parameters</td>
                        <td class="table-num">${overview["A"]}</td>
                    </tr>
                    <tr class="hline">
                        <td>${bullet++}.</td>
                        <td>Number of calibration orders</td>
                        <td class="table-num">${overview["Upsilon"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of units of each order</td>
                        <td class="table-num">[ ${overview["UpsilonUnits"]} ]</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of 2D-observations</td>
                        <td class="table-num">${overview["L"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of unknowns in the system</td>
                        <td class="table-num">${overview["unknowns"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of equations in the system</td>
                        <td class="table-num">${overview["equations"]}</td>
                    </tr>
                    <tr  class="hline">
                        <td>${bullet++}.</td>
                        <td>Size of reduced normal matrix of the system</td>
                        <td class="table-num">${overview["m"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Mission beginning</td>
                        <td class="table-num">${formatDate(new Date(overview["startTime"] * 1000))}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Mission end</td>
                        <td class="table-num">${formatDate(new Date(overview["endTime"] * 1000))}</td>
                    </tr>
                </table>
            </div>
            <div class="report-dashbox">
                <h3>AJAS Statistics</h3>
                <table>
                    <tr>
                        <td>${bullet = 1, bullet++}.</td>
                        <td>AJAS Git hash</td>
                        <td class="table-num">${stats["gitHash"].substring(0, 8)}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Process grid</td>
                        <td class="table-num">${stats["gridWidth"]} ⨯ ${stats["gridHeight"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Number of building threads per process</td>
                        <td class="table-num">${stats["buildThreads"]}</td>
                    </tr>
                    <tr class="hline">
                        <td>${bullet++}.</td>
                        <td>Number of summation threads per process</td>
                        <td class="table-num">${stats["sumThreads"]}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Matrix building time</td>
                        <td class="table-num">${formatTime(stats["matrixBuildingTime"])}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Eigenproblem solving time</td>
                        <td class="table-num">${formatTime(stats["eigenSolvingTime"])}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Eigenvalues filtering time</td>
                        <td class="table-num">${formatTime(stats["eigenFilteringTime"])}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Pseudoinverse matrix calculation time</td>
                        <td class="table-num">${formatTime(stats["pseudoInverseTime"])}</td>
                    </tr>
                    <tr class="hline">
                        <td>${bullet++}.</td>
                        <td>Backsubstitution and resudiuals calculation time</td>
                        <td class="table-num">${formatTime(stats["residualsTime"])}</td>
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Total solving time</td>
                        <td class="table-num">${formatTime(stats["matrixBuildingTime"] + stats["eigenSolvingTime"] + stats["eigenFilteringTime"] + stats["pseudoInverseTime"] + stats["residualsTime"])}</td>
                    </tr>
                </table>
            </div>
            <div class="report-dashbox">
                <h3>Sanity Checks</h3>
                <table>
                    <tr>
                        <td>${bullet = 1, bullet++}.</td>
                        <td>Calibration units</td>
                        ${sanCheck(sanity["calibUnits"])}
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Sources</td>
                        ${sanCheck(sanity["sources"])}
                    </tr>
                    <tr>
                        <td>${bullet++}.</td>
                        <td>Spectrum</td>
                        ${sanCheck(sanity["spectrum"])}
                    </tr>
                </table>
            </div>
        </div>
    `;

    report.innerHTML = html;
}

if (IN_VISUALIZATION && HAS_INPUT["Solution"] && INPUT["Solution"] != null)
{
    buildOverview(INPUT["Solution"]);
}
